f=open('/app/image.ppm')
assert f.readline().strip()=='P3'
W,H=map(int,f.readline().split())
f.readline()
vals=list(map(int,f.read().split()))
def pix(x,y):
    i=(y*W+x)*3
    return tuple(vals[i:i+3])
mins=[999,999,999]; maxs=[-1,-1,-1]; pts_min=[None]*3; pts_max=[None]*3
samples=[]
for y in range(H):
  for x in range(W):
    r,g,b=pix(x,y)
    if r>50 and g<50 and b<50:
      if (x,y) in [(1200,993),(1200,809),(1200,1177),(1016,993),(1383,993),(1120,920),(1280,920)]: samples.append(((x,y),(r,g,b)))
      for i,v in enumerate((r,g,b)):
        if v<mins[i]: mins[i]=v; pts_min[i]=(x,y)
        if v>maxs[i]: maxs[i]=v; pts_max[i]=(x,y)
print('sphere_channel_min',mins,pts_min)
print('sphere_channel_max',maxs,pts_max)
for s in samples: print('sample',s)
# global max luminance on sphere
best=None
for y in range(H):
  for x in range(W):
    r,g,b=pix(x,y)
    if r>50 and g<50 and b<50:
      L=r+g+b
      if best is None or L>best[0]: best=(L,x,y,(r,g,b))
print('brightest_sphere',best)
